#!/usr/bin/env python3
"""
Google App Engine - Flask Application with Cloud Datastore
This demonstrates the Standard Environment setup with Python runtime
"""

from flask import Flask, render_template, request, redirect, url_for
from google.cloud import datastore
from google.cloud import storage
import datetime
import os

# Initialize Flask app
app = Flask(__name__)

# Initialize Google Cloud Datastore client
# In production, this uses GOOGLE_CLOUD_PROJECT env variable
datastore_client = datastore.Client()

# Initialize Cloud Storage client
storage_client = storage.Client()
bucket_name = os.environ.get('GCS_BUCKET_NAME', 'my-app-bucket')


# ==================== DATA MODEL ====================

class Task:
    """Represents a task entity in Datastore"""

    def __init__(self, title, description, completed=False):
        self.title = title
        self.description = description
        self.completed = completed
        self.created = datetime.datetime.utcnow()

    def to_dict(self):
        return {
            'title': self.title,
            'description': self.description,
            'completed': self.completed,
            'created': self.created
        }


# ==================== ROUTES ====================

@app.route('/')
def index():
    """Home page - display all tasks"""
    query = datastore_client.query(kind='Task')
    # Order by creation date descending
    query.order = ['-created']
    tasks = list(query.fetch(limit=100))

    # Get current user info
    from google.appengine.api import users
    current_user = users.get_current_user()

    return render_template('index.html', 
                         tasks=tasks, 
                         user=current_user)


@app.route('/task/add', methods=['POST'])
def add_task():
    """Add a new task to Datastore"""
    title = request.form.get('title', '')
    description = request.form.get('description', '')

    if title:
        # Create new entity
        key = datastore_client.key('Task')
        entity = datastore.Entity(key)
        entity.update({
            'title': title,
            'description': description,
            'completed': False,
            'created': datetime.datetime.utcnow()
        })
        datastore_client.put(entity)

        # Invalidate cache
        from google.appengine.api import memcache
        memcache.delete('all_tasks')

    return redirect(url_for('index'))


@app.route('/task/<int:task_id>/toggle', methods=['POST'])
def toggle_task(task_id):
    """Toggle task completion status"""
    key = datastore_client.key('Task', task_id)
    task = datastore_client.get(key)

    if task:
        task['completed'] = not task.get('completed', False)
        datastore_client.put(task)

        # Update cache
        from google.appengine.api import memcache
        memcache.delete('all_tasks')

    return redirect(url_for('index'))


@app.route('/task/<int:task_id>/delete', methods=['POST'])
def delete_task(task_id):
    """Delete a task"""
    key = datastore_client.key('Task', task_id)
    datastore_client.delete(key)

    # Clear cache
    from google.appengine.api import memcache
    memcache.delete('all_tasks')

    return redirect(url_for('index'))


# ==================== API ENDPOINTS ====================

@app.route('/api/tasks', methods=['GET'])
def api_get_tasks():
    """REST API to get all tasks as JSON"""
    from google.appengine.api import memcache

    # Try cache first
    cached_tasks = memcache.get('all_tasks')
    if cached_tasks is not None:
        return cached_tasks

    # Query datastore
    query = datastore_client.query(kind='Task')
    query.order = ['-created']
    tasks = list(query.fetch(limit=100))

    # Convert to JSON-serializable format
    task_list = []
    for task in tasks:
        task_dict = dict(task)
        task_dict['id'] = task.key.id
        task_list.append(task_dict)

    import json
    response = json.dumps(task_list)

    # Store in cache for 5 minutes
    memcache.set('all_tasks', response, time=300)

    return response


# ==================== AUTHENTICATION ====================

@app.route('/login')
def login():
    """Google authentication login"""
    from google.appengine.api import users
    import urllib

    user = users.get_current_user()
    if user:
        return redirect(url_for('index'))
    else:
        login_url = users.create_login_url(dest_url=url_for('index'))
        return redirect(login_url)


@app.route('/logout')
def logout():
    """Google authentication logout"""
    from google.appengine.api import users

    logout_url = users.create_logout_url(url_for('index'))
    return redirect(logout_url)


# ==================== BACKGROUND TASKS ====================

from google.cloud import tasks_v2
from flask import jsonify

@app.route('/queue/task', methods=['POST'])
def queue_background_task():
    """Add a task to Cloud Tasks queue"""
    client = tasks_v2.CloudTasksClient()
    parent = client.queue_path('my-project', 'us-central1', 'my-queue')

    task = {
        'http_request': {
            'http_method': 'POST',
            'url': 'https://my-app.ue.r.appspot.com/worker/process',
            'headers': {'Content-Type': 'application/json'}
        }
    }
    client.create_task(parent=parent, task=task)

    return jsonify({'status': 'task queued'})


# ==================== ERROR HANDLERS ====================

@app.errorhandler(404)
def error_404(e):
    return render_template('error.html', error='Page not found'), 404

@app.errorhandler(500)
def error_500(e):
    return render_template('error.html', error='Server error'), 500


# ==================== MAIN ====================

if __name__ == '__main__':
    # This is used when running locally only
    app.run(host='127.0.0.1', port=8080, debug=True)

package com.example.myapp;

import com.google.cloud.datastore.*;
import com.google.appengine.api.users.User;
import com.google.appengine.api.users.UserService;
import com.google.appengine.api.users.UserServiceFactory;
import com.google.appengine.api.memcache.MemcacheService;
import com.google.appengine.api.memcache.MemcacheServiceFactory;

import javax.servlet.annotation.WebServlet;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.util.List;

/**
 * Google App Engine - Java Servlet Example
 * Demonstrates Standard Environment with Java runtime
 */
@WebServlet(name = "TaskServlet", urlPatterns = {"/tasks", "/task/add"})
public class TaskServlet extends HttpServlet {

    private Datastore datastore;
    private UserService userService;
    private MemcacheService memcache;

    @Override
    public void init() {
        // Initialize Google Cloud services
        datastore = DatastoreOptions.getDefaultInstance().getService();
        userService = UserServiceFactory.getUserService();
        memcache = MemcacheServiceFactory.getMemcacheService();
    }

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws IOException {

        String pathInfo = request.getPathInfo();

        if (pathInfo == null || pathInfo.equals("/")) {
            // Display list of tasks
            listTasks(request, response);
        } else {
            response.sendError(HttpServletResponse.SC_NOT_FOUND);
        }
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws IOException {

        String pathInfo = request.getPathInfo();

        if ("/add".equals(pathInfo)) {
            addTask(request, response);
        } else {
            response.sendError(HttpServletResponse.SC_NOT_FOUND);
        }
    }

    /**
     * List all tasks from Datastore
     */
    private void listTasks(HttpServletRequest request, HttpServletResponse response)
            throws IOException {

        // Check cache first
        String cacheKey = "all_tasks";
        String cachedData = (String) memcache.get(cacheKey);

        if (cachedData != null) {
            request.setAttribute("tasksJson", cachedData);
        } else {
            // Query Datastore
            Query<Entity> query = Query.newEntityQueryBuilder()
                .setKind("Task")
                .setOrderBy(Query.OrderByDesc("created"))
                .build();

            QueryResults<Entity> results = datastore.run(query);

            StringBuilder json = new StringBuilder("[");
            boolean first = true;
            while (results.hasNext()) {
                Entity task = results.next();
                if (!first) json.append(",");
                first = false;

                json.append("{\"id\":").append(task.getKey().getId());
                json.append(",\"title\":\"").append(task.getString("title")).append("\"");
                json.append(",\"completed\":").append(task.getBoolean("completed")).append("}");
            }
            json.append("]");

            String taskJson = json.toString();

            // Store in cache for 5 minutes
            memcache.put(cacheKey, taskJson, MemcacheService.Expiration.byDeltaSeconds(300));

            request.setAttribute("tasksJson", taskJson);
        }

        // Check authentication
        User currentUser = userService.getCurrentUser();
        request.setAttribute("user", currentUser);
        request.setAttribute("loginUrl", userService.createLoginURL("/tasks"));
        request.setAttribute("logoutUrl", userService.createLogoutURL("/tasks"));

        // Forward to JSP
        request.getRequestDispatcher("/WEB-INF/views/tasks.jsp").forward(request, response);
    }

    /**
     * Add a new task to Datastore
     */
    private void addTask(HttpServletRequest request, HttpServletResponse response)
            throws IOException {

        // Check authentication
        if (!userService.isUserLoggedIn()) {
            response.sendRedirect(userService.createLoginURL("/tasks"));
            return;
        }

        String title = request.getParameter("title");
        String description = request.getParameter("description");

        if (title != null && !title.trim().isEmpty()) {
            // Create new entity with automatic ID
            Key taskKey = datastore.newKeyFactory().setKind("Task").newKey();
            Entity task = Entity.newBuilder(taskKey)
                .set("title", title)
                .set("description", description != null ? description : "")
                .set("completed", false)
                .set("created", Timestamp.now())
                .set("userId", userService.getCurrentUser().getUserId())
                .build();

            datastore.put(task);

            // Invalidate cache
            memcache.delete("all_tasks");
        }

        response.sendRedirect("/tasks");
    }

    /**
     * Handle task completion toggle
     */
    public void toggleTask(HttpServletRequest request, HttpServletResponse response)
            throws IOException {

        String taskIdStr = request.getParameter("id");
        if (taskIdStr != null) {
            long taskId = Long.parseLong(taskIdStr);
            Key taskKey = datastore.newKeyFactory().setKind("Task").newKey(taskId);

            Transaction tx = datastore.newTransaction();
            try {
                Entity task = tx.get(taskKey);
                if (task != null) {
                    boolean currentStatus = task.getBoolean("completed");
                    Entity updatedTask = Entity.newBuilder(task)
                        .set("completed", !currentStatus)
                        .build();
                    tx.put(updatedTask);

                    // Clear cache
                    memcache.delete("all_tasks");
                }
                tx.commit();
            } finally {
                if (tx.isActive()) {
                    tx.rollback();
                }
            }
        }

        response.sendRedirect("/tasks");
    }
}

/**
 * Cron job servlet for scheduled tasks
 */
@WebServlet(name = "CronServlet", urlPatterns = {"/cron/cleanup"})
public class CronServlet extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws IOException {

        // Verify cron request
        String header = request.getHeader("X-Appengine-Cron");
        if (!"true".equals(header)) {
            response.sendError(HttpServletResponse.SC_FORBIDDEN);
            return;
        }

        // Perform cleanup operations
        Datastore datastore = DatastoreOptions.getDefaultInstance().getService();

        // Query and delete old completed tasks
        Query<Entity> query = Query.newEntityQueryBuilder()
            .setKind("Task")
            .setFilter(StructuredQuery.PropertyFilter.eq("completed", true))
            .build();

        datastore.run(query).forEachRemaining(task -> {
            datastore.delete(task.getKey());
        });

        response.setStatus(HttpServletResponse.SC_OK);
        response.getWriter().write("Cleanup completed");
    }
}
